from openai import OpenAI

# Ollama exposes an OpenAI-compatible endpoint locally
client = OpenAI(base_url="http://localhost:11434/v1", api_key="ollama")

def extract_parties(contract_text: str) -> dict:
    response = client.chat.completions.create(
        model="mistral:13b-instruct-q4_K_M",
        messages=[
            {
                "role": "system",
                "content": (
                    "You are a legal document parser. "
                    "Extract the contracting parties, effective date, and governing law "
                    "as JSON with keys: parties (list), effective_date (ISO-8601 or null), governing_law (str or null)."
                ),
            },
            {"role": "user", "content": contract_text[:8000]},
        ],
        response_format={"type": "json_object"},
        temperature=0.0,
    )
    import json
    return json.loads(response.choices[0].message.content)

